1	interface Item {
2	  type: string;
3	  cursed?: boolean;
4	  enchantment?: number;
5	}
6	
7	interface Policy {
8	  items: Item[];
9	  customer: { yearsWithMHPCO: number };
10	  isFollowUp: boolean;
11	}
12	
13	const PROCESSING_FEE = 5;
14	const FIRST_INSURANCE_RATE = 0.1;
15	const BASE_PREMIUM: Record<string, number> = { sword: 100, staff: 80, potion: 40, rune: 25, moonstone: 25 };
16	const DEFAULT_BASE_PREMIUM = 60;
17	
18	const CURSE_SURCHARGE_RATE = 0.5;
19	const HIGH_ENCHANTMENT_THRESHOLD = 5;
20	const HIGH_ENCHANTMENT_SURCHARGE_RATE = 0.3;
21	const LOYALTY_THRESHOLD = 2;
22	const LOYALTY_DISCOUNT_RATE = 0.2;
23	const BLOCK_SIZE = 3;
24	const BLOCK_PREMIUM = 60;
25	
26	function basePremiumForType(type: string): number {
27	  return BASE_PREMIUM[type] ?? DEFAULT_BASE_PREMIUM;
28	}
29	
30	function itemSurcharges(item: Item): number {
31	  const base = basePremiumForType(item.type);
32	  let surcharge = 0;
33	  if (item.cursed) {
34	    surcharge += base * CURSE_SURCHARGE_RATE;
35	  }
36	  if (item.enchantment !== undefined && item.enchantment >= HIGH_ENCHANTMENT_THRESHOLD) {
37	    surcharge += base * HIGH_ENCHANTMENT_SURCHARGE_RATE;
38	  }
39	  return surcharge;
40	}
41	
42	function countByType(items: Item[]): Record<string, number> {
43	  const counts: Record<string, number> = {};
44	  for (const item of items) {
45	    counts[item.type] = (counts[item.type] ?? 0) + 1;
46	  }
47	  return counts;
48	}
49	
50	function itemGroupPremium(type: string, count: number): number {
51	  if (count === BLOCK_SIZE) {
52	    return BLOCK_PREMIUM;
53	  }
54	  return count * basePremiumForType(type);
55	}
56	
57	export function quote(policy: Policy) {
58	  const counts = countByType(policy.items);
59	
60	  let basePremium = 0;
61	  for (const [type, count] of Object.entries(counts)) {
62	    basePremium += itemGroupPremium(type, count);
63	  }
64	
65	  let totalItemSurcharges = 0;
66	  for (const item of policy.items) {
67	    totalItemSurcharges += itemSurcharges(item);
68	  }
69	
70	  const firstInsuranceSurcharge = basePremium * FIRST_INSURANCE_RATE;
71	  const isLoyalCustomer = policy.customer.yearsWithMHPCO >= LOYALTY_THRESHOLD;
72	  const loyaltyDiscount = isLoyalCustomer ? basePremium * LOYALTY_DISCOUNT_RATE : 0;
73	  const premium = Math.ceil(basePremium + totalItemSurcharges - loyaltyDiscount + firstInsuranceSurcharge + PROCESSING_FEE);
74	  return { premium };
75	}
76	
77	export function claim() {
78	  return undefined;
79	}
