it("second quote in scenario (0 years), plain sword => premium 100 G (100 + 10 first-ins - 15 follow-up + 5 fee)", () => {
  const result = quote({
    items: [{ type: "sword" }],
    customer: { yearsWithMHPCO: 0 },
    isFollowUp: true,
  });
